</div>\n</script>\n\n<script type=\"text/template\" id=\"tmpl-elementor-templates-modal__header__logo\">\n	<span class=\"elementor-templates-modal__header__logo__icon-wrapper e-logo-wrapper\">\n		<i class=\"eicon-elementor-circle\"></i>\n	</span>\n	<span class=\"elementor-templates-modal__header__logo__title\">{{{ title }}}</span>\n</script>\n<script type=\"text/template\" id=\"tmpl-elementor-finder\">\n	<div id=\"elementor-finder__search\">\n		<i class=\"eicon-search\" aria-hidden=\"true\"></i>\n		<input id=\"elementor-finder__search__input\" placeholder=\"Type to find anything in Elementor\" autocomplete=\"off\">\n	</div>\n	<div id=\"elementor-finder__content\"></div>\n</script>\n\n<script type=\"text/template\" id=\"tmpl-elementor-finder-results-container\">\n	<div id=\"elementor-finder__no-results\">No Results Found</div>\n	<div id=\"elementor-finder__results\"></div>\n</script>\n\n<script type=\"text/template\" id=\"tmpl-elementor-finder__results__category\">\n	<div class=\"elementor-finder__results__category__title\">{{{ title }}}</div>\n	<div class=\"elementor-finder__results__category__items\"></div>\n</script>\n\n<script type=\"text/template\" id=\"tmpl-elementor-finder__results__item\">\n	<a href=\"{{ url }}\" class=\"elementor-finder__results__item__link\">\n		<div class=\"elementor-finder__results__item__icon\">\n			<i class=\"eicon-{{{ icon }}}\" aria-hidden=\"true\"></i>\n		</div>\n		<div class=\"elementor-finder__results__item__title\">{{{ title }}}</div>\n		<# if ( description ) { #>\n			<div class=\"elementor-finder__results__item__description\">- {{{ description }}}</div>\n		<# } #>\n\n		<# if ( lock ) { #>\n		<div class=\"elementor-finder__results__item__badge\"><i class=\"{{{ lock.badge.icon }}}\"></i>{{ lock.badge.text }}</div>\n		<# } #>\n	</a>\n	<# if ( actions.length ) { #>\n		<div class=\"elementor-finder__results__item__actions\">\n		<# jQuery.each( actions, function() { #>\n			<a class=\"elementor-finder__results__item__action elementor-finder__results__item__action--{{ this.name }}\" href=\"{{ this.url }}\" target=\"_blank\">\n				<i class=\"eicon-{{{ this.icon }}}\"></i>\n			</a>\n		<# } ); #>\n		</div>\n	<# } #>\n</script>\n		<script type=\"text/javascript\">\n			document.addEventListener(\'DOMContentLoaded\', function () {\n				// Upgrade link handler.\n				// IMPORTANT: If this URL changes, also update it in the `add_upgrade_to_pro` function.\n				const upgradeLink = document.querySelector(\'a[href*=\"https://ultimateelementor.com/pricing/?utm_source=wp-admin&utm_medium=menu&utm_campaign=uae-upgrade\"]\');\n				if (upgradeLink) {\n					upgradeLink.addEventListener(\'click\', e => {\n						e.preventDefault();\n						window.open(upgradeLink.href, \'_blank\');\n					});\n				}\n\n				// Get Help link handler.\n				const getHelpLink = document.querySelector(\'a[href*=\"https://ultimateelementor.com/docs\"]\');\n				if (getHelpLink) {\n					getHelpLink.addEventListener(\'click\', e => {\n						e.preventDefault();\n						window.open(getHelpLink.href, \'_blank\');\n					});\n				}\n			});\n		</script>\n			<div id=\"wp-auth-check-wrap\" class=\"hidden\">\n	<div id=\"wp-auth-check-bg\"></div>\n	<div id=\"wp-auth-check\">\n	<button type=\"button\" class=\"wp-auth-check-close button-link\"><span class=\"screen-reader-text\">\n		Close dialog	</span></button>\n			<div id=\"wp-auth-check-form\" class=\"loading\" data-src=\"http://refops.local/wp-login.php?interim-login=1&#038;wp_lang=en_US\"></div>\n			<div class=\"wp-auth-fallback\">\n		<p><b class=\"wp-auth-fallback-expired\" tabindex=\"0\">Session expired</b></p>\n		<p><a href=\"http://refops.local/wp-login.php\" target=\"_blank\">Please log in again.</a>\n		The login page will open in a new tab. After logging in you can close it and return to this page.</p>\n	</div>\n	</div>\n	</div>\n	<link rel=\'stylesheet\' id=\'hfe-style-css\' href=\'http://refops.local/wp-content/plugins/header-footer-elementor/assets/css/style.css?ver=2.8.6\' media=\'all\' />\n<link