per\">\n	<div id=\"hfe-menu-page\">\n		<div class=\"hfe-menu-page-content hfe-clear\">\n			\n<div id=\"hfe-settings-app\" class=\"hfe-settings-app\">\n\n</div>\n		</div>\n	</div>\n</div>\n\n<div class=\"clear\"></div></div><!-- wpbody-content -->\n<div class=\"clear\"></div></div><!-- wpbody -->\n<div class=\"clear\"></div></div><!-- wpcontent -->\n\n<div id=\"wpfooter\" role=\"contentinfo\">\n		<p id=\"footer-left\" class=\"alignleft\">\n		Enjoyed <b>UAE</b>? Please leave us a <a class=\"uae-rating\" href=\"https://wordpress.org/support/plugin/header-footer-elementor/reviews/#new-post\" target=\"_blank\">★★★★★</a> rating. We really appreciate your support!	</p>\n	<p id=\"footer-upgrade\" class=\"alignright\">\n		Version 6.9.4	</p>\n	<div class=\"clear\"></div>\n</div>\n            <script type=\"text/javascript\">\n                (function ( $ ) {\n                    $( \'.fs-submenu-item\' ).each( function () {\n                        var $this = $( this ),\n                            $parent = $this.parent(),\n                            externalLink = $this.data( \'fs-external-url\' ),\n                            isOpensInNewTab = $this.data( \'fs-new-tab\' );\n\n                        if ( externalLink ) {\n                            $parent.attr( \'href\', externalLink );\n                        }\n\n                        if ( isOpensInNewTab ) {\n                            $parent.attr( { target: \'_blank\', rel: \'noopener noreferrer\' } );\n                        }\n                    } );\n                } )( jQuery );\n            </script>\n            \n<script type=\"text/template\" id=\"tmpl-ast-image-skeleton\">\n	<div class=\"ast-image__skeleton-wrap\">\n		<div class=\"ast-image__skeleton-inner-wrap\">\n			<div class=\"ast-image__skeleton\">\n			</div>\n			<div class=\"ast-image__preview-skeleton\">\n			</div>\n		</div>\n	</div>\n	<div class=\"ast-image__loader-wrap\">\n		<div class=\"ast-image__loader-1\"></div>\n		<div class=\"ast-im